class Solution:
    def videoStitching(self, clips, time):
        # Brute force DP: dp[t] = min clips to cover [0, t].
        INF = float('inf')
        dp = [0] + [INF] * time
        for t in range(1, time + 1):
            for a, b in clips:
                if a < t <= b:
                    if dp[a] + 1 < dp[t]:
                        dp[t] = dp[a] + 1
        return -1 if dp[time] == INF else dp[time]

