class Solution:
    def videoStitching(self, clips, time):
        maxReach = [0] * (time + 1)
        for a, b in clips:
            if a <= time:
                maxReach[a] = max(maxReach[a], b)
        count = 0
        cur_end = 0
        next_end = 0
        i = 0
        while cur_end < time:
            while i <= cur_end and i <= time:
                next_end = max(next_end, maxReach[i])
                i += 1
            if next_end <= cur_end:
                return -1
            count += 1
            cur_end = next_end
        return count

