var videoStitching = function(clips, time) {
    const maxReach = new Array(time + 1).fill(0);
    for (const [a, b] of clips) {
        if (a <= time) maxReach[a] = Math.max(maxReach[a], b);
    }
    let count = 0, curEnd = 0, nextEnd = 0, i = 0;
    while (curEnd < time) {
        while (i <= curEnd && i <= time) {
            nextEnd = Math.max(nextEnd, maxReach[i]);
            i += 1;
        }
        if (nextEnd <= curEnd) return -1;
        count += 1;
        curEnd = nextEnd;
    }
    return count;
};
